package com.raku.apple_test.generics;

/**
 * りんごを受け取って表示する、ジェネリクスのラッパークラス。
 *
 * <p>M は「GenericsApple のどれか」を意味し、
 * 具体的な型を呼び出し側に任せることで柔軟さを持たせます。</p>
 */
public class RedApple<M extends GenericsApple<?>> {
    private final M fruit;

    public RedApple(M fruit) {
        this.fruit = fruit;
    }

    public M fruit() {
        return fruit;
    }

    public void eatFruit() {
        System.out.println("食べた果物： " + fruit.getName()
                + "\n 色： " + fruit.getColor()
                + "\n 重さ：" + fruit.getWeight() + " g");
    }
}

package com.raku.apple_test.generics;

/**
 * りんごを受け取って表示する、ジェネリクスのラッパークラス。
