 * <p>M は「GenericsApple のどれか」を意味し、
 * 具体的な型を呼び出し側に任せることで柔軟さを持たせます。</p>
 */
@SuppressWarnings("unused")
public class RedApple<M extends GenericsApple<?>> {
    private final M fruit;

    public RedApple(M fruit) {
        this.fruit = fruit;
